INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('f1935077973f4200', 'ME', '["federal"]', 'candidate_eligibility', 'Is Janet Mills running for Governor or U.S. Senate in 2026?', '["Who is challenging Susan Collins in 2026?","Is the Maine Senate seat up for election in 2026?","2026 US Senate race Maine candidates"]', 'Janet Mills is running for the U.S. Senate in 2026. She is term-limited as Governor and is seeking the Democratic nomination to challenge Republican incumbent Susan Collins, who is running unopposed in the Republican primary for her sixth term.', 'https://www.maine.gov/sos/elections-voting/upcoming-elections', 'Maine Secretary of State – Upcoming Elections', '2026-05-12', 'volatile', 'official_source_direct', 'Federal candidates and consultants', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('4b4a63a30576ef3a', 'ME', '["state"]', 'candidate_eligibility', 'Can Governor Janet Mills run for re-election in 2026?', '["Is the Maine Governor''s seat open in 2026?","What are the term limits for Maine Governor?","Can Mills seek a third term?"]', 'No. The Maine Constitution limits the Governor to serving two consecutive four-year terms. Because Governor Mills was elected in 2018 and 2022, she is term-limited, making the 2026 gubernatorial race an open seat.', 'https://legislature.maine.gov/const/#Article_V_Part_1', 'Maine Constitution Article V Part 1 § 2', '2026-05-12', 'static', 'statute_citation', 'Statewide candidates', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('8601aa416772c00f', 'ME', '["federal","state"]', 'runoff_rules', 'Does Maine use Ranked-Choice Voting (RCV) for all elections?', '["Is ranked choice voting used for Governor in ME?","RCV rules Maine general election","LD 1666 Maine Supreme Court ruling"]', 'No. RCV is used for ALL state and federal primaries, and for FEDERAL general elections only. In an April 6, 2026 advisory opinion on LD 1666, the Maine Supreme Judicial Court definitively reaffirmed that using RCV for state general elections (Governor, Legislature) violates the ''plurality'' requirement established in the Maine Constitution (Art. IV & Art. V).', 'https://legislature.maine.gov/statutes/21-A/title21-Asec723-A.html', '21-A M.R.S. § 723-A', '2026-05-12', 'static', 'statute_citation', 'All candidates and voters', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('d955bc5f6493d5bb', 'ME', '["federal","state","county","municipal","judicial"]', 'election_dates', 'When is the 2026 Maine Primary Election?', '["What date is the ME primary in 2026?","Maine 2026 primary date","When do polls open for the ME primary?"]', 'The Maine Primary Election is on Tuesday, June 9, 2026. Maine statutorily holds its primary on the second Tuesday of June.', 'https://www.maine.gov/sos/elections-voting/upcoming-elections', 'Maine Secretary of State – Upcoming Elections', '2026-05-12', 'per_cycle', 'official_source_direct', 'All candidates and voters', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('57604566bc7d859b', 'ME', '["federal","state","county","municipal","judicial"]', 'election_dates', 'When is the 2026 Maine General Election?', '["What date is the ME general election in 2026?","ME 2026 midterm election date","When is Election Day 2026 in Maine?"]', 'The Maine General Election is on Tuesday, November 3, 2026.', 'https://www.maine.gov/sos/elections-voting/upcoming-elections', 'Maine Secretary of State – Upcoming Elections', '2026-05-12', 'per_cycle', 'official_source_direct', 'All candidates and voters', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('11e355f96b65e18e', 'ME', '["federal","state","county"]', 'ballot_access', 'What was the candidate filing deadline for major party candidates for the 2026 primary?', '["When did candidates have to file for the 2026 primary in Maine?","Primary nomination petition deadline 2026","Maine March filing deadline"]', 'The deadline for major party candidates to file their primary nomination petitions and consent forms with the Division of Elections was March 16, 2026, at 5:00 p.m.', 'https://www.maine.gov/sos/elections-voting/becoming-a-candidate', 'Maine Secretary of State – Becoming a Candidate', '2026-05-12', 'per_cycle', 'official_source_direct', 'Major party candidates', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('9c269fc6334ce2a4', 'ME', '["federal","state","county"]', 'ballot_access', 'When is the filing deadline for Nonparty (Independent) candidates in Maine for 2026?', '["Running as an independent in ME","Independent ballot access deadline Maine","When are nonparty petitions due?"]', 'Nonparty (Independent) candidates bypass the primary and must submit their nonparty nomination petitions to the Division of Elections by 5:00 p.m. on June 1, 2026. The window to collect these signatures opened on January 1, 2026.', 'https://www.maine.gov/sos/elections-voting/upcoming-elections', 'Maine Secretary of State – Upcoming Elections', '2026-05-12', 'per_cycle', 'official_source_direct', 'Independent and third-party candidates', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('65843dc91b3e9b46', 'ME', '["federal","state","county","municipal"]', 'voter_interaction', 'Does Maine have an open or closed primary?', '["Can an independent vote in the Maine Democratic primary?","Semi-open primary rules ME","Do I have to be registered to a party to vote in the primary?"]', 'Maine has a semi-open primary. Unenrolled voters (independents) are legally permitted to vote in either the Democratic or Republican primary without having to formally enroll in that party. However, a voter already enrolled in one party cannot vote in the other party''s primary.', 'https://www.maine.gov/sos/elections-voting/upcoming-elections', 'Maine Secretary of State – Upcoming Elections', '2026-05-12', 'static', 'official_source_direct', 'Voters and Get-Out-The-Vote operations', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('1d9885f3276ddc32', 'ME', '["state"]', 'finance_ethics', 'What is the Maine Clean Election Act (MCEA)?', '["State public financing ME","How does the Clean Elections system work?","Do Maine candidates get public money?"]', 'The MCEA is a voluntary full public financing program for candidates running for Governor, State Senate, and State Representative. Candidates collect a required number of $5 qualifying contributions from registered voters to demonstrate support. Once certified, they receive a block of public funds and agree not to accept any private donations.', 'https://www.maine.gov/ethics/clean-elections', 'Maine Ethics Commission – Clean Elections', '2026-05-12', 'static', 'official_source_direct', 'State-level candidates', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('bba12ac465cd105e', 'ME', '["state"]', 'finance_ethics', 'How many $5 qualifying contributions are required to receive MCEA funding for Governor in 2026?', '["Clean Election threshold for Governor ME","How many $5 donations to qualify for public financing?","MCEA gubernatorial requirement"]', 'To qualify for full public financing under the MCEA, a gubernatorial candidate must collect exactly 3,200 qualifying $5 contributions from registered Maine voters. Upon certification for a contested election, the candidate receives an initial primary grant of $530,125 and an initial general election grant of $795,175, with additional supplemental funds possible.', 'https://www.maine.gov/ethics/candidates/mcea-gubernatorial', 'Maine Ethics Commission – MCEA Gubernatorial Candidates', '2026-05-12', 'per_cycle', 'official_source_direct', 'Gubernatorial candidates participating in MCEA', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('b4380f4d66c3385b', 'ME', '["state"]', 'finance_ethics', 'How many $5 qualifying contributions are required for State Senate and State House candidates under the MCEA?', '["Clean Election threshold for State Legislature ME","How many $5 donations for State Senate public funding?","MCEA legislative requirement"]', 'For the 2026 cycle, a State Senate candidate must collect 175 qualifying $5 contributions to receive an initial grant of $20,000. A State House candidate must collect 60 qualifying $5 contributions to receive an initial grant of $5,000. These amounts represent initial base distributions for contested elections.', 'https://www.maine.gov/ethics/candidates/mcea-legislative', 'Maine Ethics Commission – MCEA Legislative Candidates', '2026-05-12', 'per_cycle', 'official_source_direct', 'State Legislative candidates participating in MCEA', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('6dd707ae2d81d390', 'ME', '["state"]', 'election_dates', 'How are the Secretary of State, Attorney General, and State Treasurer selected in Maine?', '["Are there elections for Secretary of State in ME?","Maine Attorney General appointment","Statewide executive elections ME"]', 'Unlike most states, Maine''s Secretary of State, Attorney General, and State Treasurer are NOT elected by the voters. Under the Maine Constitution, all three constitutional officers are appointed by a joint ballot of the State Legislature to serve two-year terms, matching the legislative session.', 'https://legislature.maine.gov/const/', 'Maine Constitution Article V Parts 2, 4 & 5', '2026-05-12', 'static', 'statute_citation', 'Statewide executive candidates and Consultants', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('bdbe36224f35c2e7', 'ME', '["federal","state","county","municipal"]', 'candidate_eligibility', 'Can a person with a felony conviction vote in Maine while incarcerated?', '["Felon voting rights ME","Can prisoners vote in Maine?","Voting post-incarceration rules ME"]', 'Yes. Maine is one of only two U.S. states (along with Vermont) that never disenfranchises individuals with felony convictions. Incarcerated individuals retain the right to vote while in prison via absentee ballot, registering at their last known pre-incarceration Maine address.', 'https://legislature.maine.gov/statutes/21-A/title21-Asec111.html', '21-A M.R.S. § 111', '2026-05-12', 'static', 'statute_citation', 'All eligible citizens', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('4444fd63a95fa001', 'ME', '["federal","state","county","municipal"]', 'voter_interaction', 'Does Maine have same-day voter registration (Election Day Registration)?', '["Can I register to vote at the polls in Maine?","Same-day registration rules ME","Is there a voter registration deadline?"]', 'Yes. Maine allows voters to register in person at their town office or city hall up to and including Election Day. While mail-in and online registrations have a deadline (typically 21 days before the election), Election Day Registration (EDR) ensures eligible voters can always register and vote on the spot.', 'https://legislature.maine.gov/statutes/21-A/title21-Asec122.html', '21-A M.R.S. § 122(4)', '2026-05-12', 'static', 'statute_citation', 'Unregistered voters', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('434b9945dc73e799', 'ME', '["federal","state","county","municipal"]', 'voter_interaction', 'Is a photo ID required to vote in person in Maine?', '["Maine voter ID laws","Do I need my driver''s license to vote in ME?","Poll ID requirements Maine"]', 'No. Maine does not require voters to present photo identification at the polls to cast a ballot. Only first-time voters who registered by mail without providing a driver''s license or Social Security number may be asked to show a valid ID or proof of residence (like a utility bill) at the polls.', 'https://www.maine.gov/sos/elections-voting', 'Maine Secretary of State', '2026-05-12', 'static', 'official_source_direct', 'All voters', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('4dbdd11fb2a427b7', 'ME', '["federal"]', 'election_dates', 'How does Maine allocate its Electoral College votes for President?', '["Maine split electoral votes","Does the winner take all in Maine?","Congressional district electoral vote allocation"]', 'Maine is one of only two states (alongside Nebraska) that does not use a winner-take-all system. Maine awards two electoral votes to the statewide popular vote winner, and one electoral vote to the popular vote winner in each of its two specific congressional districts.', 'https://legislature.maine.gov/statutes/21-A/title21-Asec802.html', '21-A M.R.S. § 802', '2026-05-12', 'static', 'statute_citation', 'Federal campaigns and Consultants', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('1019c4d204df8abd', 'ME', '["federal","state","county","municipal"]', 'voter_interaction', 'Who directly administers elections and voter registration at the local level in Maine?', '["County board of elections Maine","Where do I register to vote?","Municipal clerk role ME"]', 'Unlike most states that use county-level administration, Maine administers elections at the municipal level. Every individual town and city has its own Municipal Clerk and Registrar of Voters who are entirely responsible for local voter registration, maintaining poll lists, and administering local voting locations.', 'https://legislature.maine.gov/statutes/21-A/title21-Ach3.pdf', '21-A M.R.S. § 112-A', '2026-05-12', 'static', 'statute_citation', 'Voters and Campaigns', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('a571eabff78ecbec', 'ME', '["federal","state","county","municipal"]', 'election_dates', 'What is the deadline for a mail-in absentee ballot to be received in Maine?', '["When is my absentee ballot due in ME?","Postmark rules for Maine voting","Absentee ballot receipt deadline"]', 'To be counted, an absentee ballot must be physically received by the municipal clerk before the polls close at 8:00 p.m. on Election Day. Maine does not have a postmark grace period; a ballot arriving by mail after 8:00 p.m. on Election Day will be rejected.', 'https://legislature.maine.gov/statutes/21-A/title21-Asec755.html', '21-A M.R.S. § 755', '2026-05-12', 'static', 'statute_citation', 'All voters and Campaigns', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('251ccf8ecb625887', 'ME', '["state"]', 'candidate_eligibility', 'What are the specific residency and age requirements to run for Governor of Maine?', '["How long do I need to live in ME to run for Governor?","Age requirement for Governor ME","Gubernatorial candidate qualifications"]', 'Under the Maine Constitution, a candidate for Governor must be at least 30 years old, a United States citizen for at least 15 years, and a resident of Maine for at least 5 years immediately preceding their election.', 'https://legislature.maine.gov/const/#Article_V_Part_1', 'Maine Constitution Article V Part 1 § 4', '2026-05-12', 'static', 'statute_citation', 'Gubernatorial candidates', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('a14b04885a8e27bd', 'ME', '["state"]', 'candidate_eligibility', 'What are the residency and age requirements to run for the Maine State Senate?', '["How old to run for State Senate ME?","Residency rules State Senate Maine","Do I have to live in the district?"]', 'A candidate for the Maine State Senate must be at least 25 years old, a citizen of the United States for 5 years, a resident of Maine for 1 year, and must have been a resident of the district they seek to represent for at least 3 months preceding the election.', 'https://legislature.maine.gov/const/#Article_IV_Part_2', 'Maine Constitution Article IV Part 2 § 6', '2026-05-12', 'static', 'statute_citation', 'State Senate candidates', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('913b00e05823e500', 'ME', '["state"]', 'candidate_eligibility', 'What are the residency and age requirements to run for the Maine State House of Representatives?', '["How old to run for State House ME?","Residency rules State Representative Maine","Do I have to live in the district to run for House?"]', 'A candidate for the Maine State House of Representatives must be at least 21 years old, a citizen of the United States for 5 years, a resident of Maine for 1 year, and must have been a resident of the district they seek to represent for at least 3 months preceding the election.', 'https://legislature.maine.gov/const/#Article_IV_Part_1', 'Maine Constitution Article IV Part 1 § 4', '2026-05-12', 'static', 'statute_citation', 'State House candidates', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('ba277f9ef85859e2', 'ME', '["state"]', 'candidate_eligibility', 'What are the term limits for members of the Maine State Legislature?', '["How long can someone serve in the ME House?","State Representative term limits Maine","State Senate consecutive terms"]', 'The Maine Constitution strictly limits both State Senators and State Representatives to serving four consecutive two-year terms (a total of eight years) in the same chamber. An individual may run for the other chamber to restart the clock, or sit out a cycle to reset the limit.', 'https://legislature.maine.gov/const/#Article_IV_Part_3', 'Maine Constitution Article IV Part 3 § 18', '2026-05-12', 'static', 'statute_citation', 'State Legislative candidates', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('0010f2e9cc41243f', 'ME', '["federal","state","county"]', 'filing_requirements', 'What is the candidate filing fee in Maine?', '["How much does it cost to run for office in ME?","Maine filing fee amount","Do I have to pay to get on the ballot?"]', 'Maine does not charge a filing fee to run for federal, state, or county office. Candidates access the primary or general election ballot exclusively by collecting and filing the statutorily required number of valid nomination petition signatures.', 'https://www.maine.gov/sos/elections-voting/becoming-a-candidate', 'Maine Secretary of State – Becoming a Candidate', '2026-05-12', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('712fd5fb3eb8d931', 'ME', '["federal","state"]', 'runoff_rules', 'How are votes tabulated under Ranked-Choice Voting in Maine?', '["RCV elimination rounds Maine","How does the ranked choice vote counting work?","Maine central tabulation RCV"]', 'In an RCV election, if no candidate wins a strict majority (50% + 1) of first-choice votes, the candidate with the fewest votes is eliminated. The eliminated candidate''s votes are reallocated to those voters'' second choices. These elimination rounds continue until a candidate surpasses the 50% threshold. The tabulation is centrally conducted by the Secretary of State in Augusta.', 'https://legislature.maine.gov/statutes/21-A/title21-Asec723-A.html', '21-A M.R.S. § 723-A(2)', '2026-05-12', 'static', 'statute_citation', 'Voters and Campaigns in RCV elections', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('097e3d5fae02107c', 'ME', '["state"]', 'ballot_access', 'How many petition signatures are required for a major party candidate running for Governor in Maine?', '["Signature requirement for ME Governor primary","How many signatures to run for Governor in the primary?","Gubernatorial primary petition threshold"]', 'To access the primary ballot, a major party candidate for Governor must collect at least 2,000, but not more than 3,000, valid signatures from enrolled voters of their specific political party.', 'https://legislature.maine.gov/statutes/21-A/title21-Asec335.html', '21-A M.R.S. § 335(5)', '2026-05-12', 'static', 'statute_citation', 'Gubernatorial major party candidates', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('ce6ca58ee91a672e', 'ME', '["state"]', 'ballot_access', 'How many petition signatures are required for an Independent (Nonparty) candidate running for Governor?', '["Signature requirement for ME Governor independent","How many signatures to run statewide as nonparty in ME?","Gubernatorial general election petition threshold"]', 'Independent (Nonparty) candidates seeking to bypass the primary and appear directly on the November general election ballot for Governor must collect at least 4,000, but not more than 6,000, valid signatures from registered Maine voters.', 'https://legislature.maine.gov/statutes/21-A/title21-Asec354.html', '21-A M.R.S. § 354(5)', '2026-05-12', 'static', 'statute_citation', 'Gubernatorial independent/nonparty candidates', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('fc103f115fd553cc', 'ME', '["federal"]', 'ballot_access', 'What are the signature thresholds for a U.S. Senate designating petition in Maine?', '["How many signatures to run for Senate in ME?","Senate ballot access Maine","Statewide federal signature requirements"]', 'A major party candidate for U.S. Senate needs at least 2,000 (and no more than 3,000) signatures from enrolled party voters. A Nonparty (Independent) candidate needs at least 4,000 (and no more than 6,000) signatures from registered voters to access the general election ballot.', 'https://legislature.maine.gov/statutes/21-A/title21-Asec335.html', '21-A M.R.S. § 335(5) / § 354(5)', '2026-05-12', 'static', 'statute_citation', 'U.S. Senate candidates', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('532a8b4d36d12570', 'ME', '["federal"]', 'ballot_access', 'What are the signature thresholds for a U.S. House designating petition in Maine?', '["How many signatures to run for Congress in ME?","Congressional ballot access Maine","US House primary signature requirements"]', 'A major party candidate for U.S. House needs at least 1,000 (and no more than 1,500) signatures from enrolled party voters in their district. A Nonparty (Independent) candidate needs at least 2,000 (and no more than 3,000) signatures from registered voters in their district.', 'https://legislature.maine.gov/statutes/21-A/title21-Asec335.html', '21-A M.R.S. § 335(5) / § 354(5)', '2026-05-12', 'static', 'statute_citation', 'U.S. House candidates', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('46a35e4a4227ec10', 'ME', '["state"]', 'ballot_access', 'What are the signature thresholds for State Senate and State Representative petitions in Maine?', '["Signatures needed for ME State Legislature","How many signatures to run for State Assembly ME?","State Senate petition requirements"]', 'For major party candidates, State Senate requires 100-150 signatures, and State Representative requires 25-40 signatures. For Nonparty candidates bypassing the primary, State Senate requires 200-300 signatures, and State Representative requires 50-80 signatures.', 'https://legislature.maine.gov/statutes/21-A/title21-Asec335.html', '21-A M.R.S. § 335(5) / § 354(5)', '2026-05-12', 'static', 'statute_citation', 'State Legislative candidates', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('bf4b7a549d18e015', 'ME', '["federal","state","county"]', 'ballot_access', 'When is the deadline to register as a write-in candidate in Maine?', '["Do write-in candidates have to register in ME?","How to legally canvass write-in votes","Declaration of Write-in Candidacy Maine"]', 'To have their votes counted, a write-in candidate must file a Declaration of Write-in Candidacy with the Secretary of State no later than 5:00 p.m. on the 60th day prior to the election (primary or general).', 'https://legislature.maine.gov/statutes/21-A/title21-Asec722-A.html', '21-A M.R.S. § 722-A', '2026-05-12', 'static', 'statute_citation', 'Write-in candidates', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('6016b5ce24fff15a', 'ME', '["state","county","municipal"]', 'finance_ethics', 'What is the pre-election reporting schedule for campaign committees in Maine?', '["When are campaign finance reports due in ME?","11-day pre-primary report deadline","Maine periodic campaign filing dates"]', 'Candidate committees must file two reports before an election: the 42-Day Pre-Election Report and the 11-Day Pre-Election Report. Following the election, a 42-Day Post-Election Report must be filed. This applies to both the primary and the general election.', 'https://legislature.maine.gov/statutes/21-A/title21-Asec1017.html', '21-A M.R.S. § 1017(3-A)', '2026-05-12', 'static', 'statute_citation', 'Campaign Treasurers', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('2318324a6a2ffe4b', 'ME', '["state","county","municipal"]', 'finance_ethics', 'What reporting schedule applies in Maine for years when the candidate is not on the ballot?', '["Semiannual reports Maine","Off-year campaign finance reporting ME","When to file if there''s no election"]', 'In non-election years, active candidate committees must file Semiannual Reports. These reports are due on July 15 (covering January 1 through June 30) and on January 15 (covering July 1 through December 31).', 'https://legislature.maine.gov/statutes/21-A/title21-Asec1017.html', '21-A M.R.S. § 1017(3-A)', '2026-05-12', 'static', 'statute_citation', 'Campaign Treasurers', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('4332c75dfeca29f8', 'ME', '["state","county","municipal"]', 'finance_ethics', 'What is the 24-hour reporting rule for late contributions in Maine?', '["Late contribution timeframe ME","When do I have to report donations within 24 hours?","Maine 13-day election window reporting"]', 'Under 21-A M.R.S. § 1017(3-A)(C), any single contribution, loan, or expenditure of $1,000 or more made within the 13 days immediately preceding an election must be reported to the Maine Ethics Commission within 24 hours.', 'https://legislature.maine.gov/statutes/21-A/title21-Asec1017.html', '21-A M.R.S. § 1017(3-A)(C)', '2026-05-12', 'static', 'statute_citation', 'Campaign Treasurers', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('767db4a98aba8453', 'ME', '["state"]', 'finance_ethics', 'What are the rules regarding ''Seed Money'' for MCEA participating candidates?', '["MCEA seed money caps","Can clean election candidates raise early money?","Seed money limits Maine"]', 'Before qualifying for public funding, MCEA candidates may raise limited ''seed money'' to jumpstart their campaigns. Seed money contributions are strictly capped at $100 per individual donor, and the candidate can only raise up to a specific total cap based on the office sought.', 'https://www.maine.gov/ethics/candidates/mcea-legislative', 'Maine Ethics Commission – MCEA Rules', '2026-05-12', 'static', 'official_source_direct', 'MCEA Participating Candidates', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('4bc89a2f9e4cc297', 'ME', '["state"]', 'finance_ethics', 'What are the 2025-2026 contribution limits for privately financed candidates in Maine?', '["How much can an individual give to a candidate in ME?","Traditional financing limits Maine","Max donation for Governor 2026"]', 'For the 2025-2026 cycle, individuals, PACs, and corporations may contribute up to $2,075 per election to privately financed gubernatorial candidates. For State Senate and State Representative candidates, the limit is $500 per election. (Primary and general elections count as strictly separate limits).', 'https://legislature.maine.gov/statutes/21-A/title21-Asec1015.html', '21-A M.R.S. § 1015', '2026-05-12', 'per_cycle', 'statute_citation', 'Privately financed candidates and donors', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('15738fd65a6f5154', 'ME', '["state","county","municipal"]', 'finance_ethics', 'Can a corporation contribute directly to a candidate for state office in Maine?', '["Are corporate contributions legal in ME?","Can my business donate to a state candidate?","LLC donation limits Maine"]', 'Yes, Maine distinctly permits direct corporate treasury contributions to privately financed candidates, subject to the same limits as individuals ($2,075 for Governor, $500 for legislative races per election). Under 21-A M.R.S. § 1015-A, LLCs are treated as a single aggregated entity with their majority members.', 'https://legislature.maine.gov/statutes/21-A/title21-Asec1015-A.html', '21-A M.R.S. § 1015-A', '2026-05-12', 'static', 'statute_citation', 'Corporations, LLCs, and Campaign Treasurers', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('07601f5b82c1c719', 'ME', '["state","county","municipal"]', 'finance_ethics', 'What triggers the requirement to report an Independent Expenditure in Maine?', '["When does an independent group have to file?","Independent expenditure definition ME","Reporting threshold for Super PACs Maine"]', 'An independent expenditure is any communication advocating for the election or defeat of a candidate made independently of the campaign. Under 21-A M.R.S. § 1019-B, any person or group whose aggregate spending exceeds $250 in any one candidate''s election must file an Independent Expenditure Report.', 'https://legislature.maine.gov/statutes/21-A/title21-Asec1019-B.html', '21-A M.R.S. § 1019-B', '2026-05-12', 'static', 'statute_citation', 'Super PACs and Independent Groups', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('bbc82b87500d9ee9', 'ME', '["state","county","municipal"]', 'finance_ethics', 'What defines a Ballot Question Committee (BQC) in Maine?', '["How to register a ballot initiative group in ME","BQC reporting threshold","When do I form a committee for a referendum?"]', 'Any person or group that receives contributions or makes expenditures exceeding $5,000 to initiate or influence a ballot question must register as a Ballot Question Committee (BQC) with the Ethics Commission within 7 days of meeting the threshold.', 'https://legislature.maine.gov/statutes/21-A/title21-Asec1056-B.html', '21-A M.R.S. § 1056-B', '2026-05-12', 'static', 'statute_citation', 'Ballot Measure Committees', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('9fd5ac44eb1de90a', 'ME', '["state","county","municipal"]', 'finance_ethics', 'Are candidates in Maine allowed to use campaign funds for personal expenses?', '["Personal use of campaign funds ME","Can I buy a car with campaign money?","Maine rules on spending campaign donations"]', 'No. Maine law explicitly prohibits the conversion of campaign funds to personal use. Expenses must be directly related to the campaign or the execution of public office duties.', 'https://legislature.maine.gov/statutes/21-A/title21-Asec1014-B.html', '21-A M.R.S. § 1014-B', '2026-05-12', 'static', 'statute_citation', 'All candidates and treasurers', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('ba29ad5777746e81', 'ME', '["state","county","municipal"]', 'finance_ethics', 'Are foreign nationals prohibited from contributing to campaigns in Maine?', '["Can a foreign citizen donate to my city council race?","Foreign contribution ban ME","Are non-citizens allowed to fund independent expenditures in Maine?"]', 'Yes. Beyond mirroring federal restrictions, Maine voters recently passed Question 2 (codified as 21-A M.R.S. § 1064), which explicitly bans foreign governments and foreign government-influenced corporations from spending money in candidate elections or ballot initiatives. The ban is operational for 2026, though active litigation (SIFMA v. Bellows) is pending.', 'https://legislature.maine.gov/statutes/21-A/title21-Asec1064.html', '21-A M.R.S. § 1064', '2026-05-12', 'static', 'statute_citation', 'All state and local campaigns', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('f4c1bcb795e9cbbf', 'ME', '["state","county","municipal"]', 'finance_ethics', 'How long must a campaign treasurer retain campaign finance records in Maine?', '["Campaign record retention requirements ME","How many years to keep campaign receipts?","Ethics Commission audit record retention"]', 'A candidate''s treasurer must retain all campaign records (receipts, invoices, bank statements) for 4 years following the election to which the records pertain. The Ethics Commission actively audits 20% of MCEA campaigns.', 'https://legislature.maine.gov/statutes/21-A/title21-Asec1016.html', '21-A M.R.S. § 1016', '2026-05-12', 'static', 'statute_citation', 'Campaign Treasurers', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('622cae07e927d70c', 'ME', '["state","county","municipal"]', 'finance_ethics', 'What are the rules for disposing of surplus campaign funds for privately financed candidates in Maine?', '["Surplus funds disposition ME","Can I give my leftover campaign money to charity?","What happens to campaign money when I close my committee?"]', 'Privately financed candidates may return surplus funds pro-rata to contributors, transfer them to a political party, donate them to charity, use them for future campaign expenses, or retain them for expenses related to holding office. MCEA candidates, conversely, must return all unspent public funds to the state.', 'https://legislature.maine.gov/statutes/21-A/title21-Asec1017.html', '21-A M.R.S. § 1017(8)', '2026-05-12', 'static', 'statute_citation', 'Candidates concluding campaigns', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('803c49fdb5b1c8c5', 'ME', '["state","county","municipal"]', 'finance_ethics', 'How are campaign finance violations adjudicated in Maine?', '["Who enforces campaign finance in ME?","Maine Ethics Commission complaint process","Reporting an opponent for illegal funding"]', 'Campaign finance and ethics violations are enforced by the Maine Commission on Governmental Ethics and Election Practices (a 5-member bipartisan panel). Anyone can file a formal complaint. Commission staff investigate and present findings at public meetings, where the Commission votes on penalties.', 'https://www.maine.gov/ethics/compliance', 'Maine Ethics Commission', '2026-05-12', 'static', 'official_source_direct', 'Campaigns and Legal Counsel', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('51eada77fc765d06', 'ME', '["state","county","municipal"]', 'finance_ethics', 'What are the penalties for filing a campaign finance report late with the Maine Ethics Commission?', '["Late filing fees ME","How much is the fine for missing a reporting deadline?","Ethics Commission late penalties"]', 'Late filing penalties are calculated based on a percentage of the total contributions or expenditures for the reporting period, multiplied by the number of days late. The maximum penalty caps out at $10,000 for statewide and legislative candidates.', 'https://legislature.maine.gov/statutes/21-A/title21-Asec1020-A.html', '21-A M.R.S. § 1020-A', '2026-05-12', 'static', 'statute_citation', 'Campaign Treasurers', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('7aa404e58ea55a7d', 'ME', '["federal","state","county","municipal"]', 'finance_ethics', 'What are the disclosure requirements for digital advertising and robocalls in Maine?', '["Do Facebook ads need disclaimers in Maine?","Robocall disclosure requirements ME","Digital political ad rules"]', 'Any communication made to influence an election—including print, broadcast, digital advertising, SMS texts, and robocalls—must clearly state who paid for and authorized the message (e.g., ''Paid for and authorized by the Candidate'').', 'https://legislature.maine.gov/statutes/21-A/title21-Asec1014.html', '21-A M.R.S. § 1014', '2026-05-12', 'static', 'statute_citation', 'Digital Strategists and Campaigns', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('759adfc801d0c2b7', 'ME', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the deadline for an unregistered voter to register by mail in Maine?', '["Voter registration deadline by mail ME","When is the last day to mail in a registration card?","21 day registration rule Maine"]', 'Voter registration applications submitted by mail, through a voter registration drive, or online must be received by the municipal clerk by the close of business on the 21st day before the election. After this deadline, voters must register in person.', 'https://www.maine.gov/sos/elections-voting/voter-registration', 'Maine Secretary of State – Voter Registration', '2026-05-12', 'static', 'official_source_direct', 'Unregistered voters', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('a5ae6c3b7176f67d', 'ME', '["federal","state","county","municipal"]', 'voter_interaction', 'Does Maine allow no-excuse absentee voting?', '["Can anyone vote by mail in ME?","Do I need an excuse to get an absentee ballot?","Absentee voting rules Maine"]', 'Yes. Any registered Maine voter may request an absentee ballot without providing a reason. Absentee ballots become available 30 days before the election.', 'https://www.maine.gov/sos/elections-voting/absentee', 'Maine Secretary of State – Absentee Voting', '2026-05-12', 'static', 'official_source_direct', 'All voters', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('459a8760b07135d4', 'ME', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the deadline to request an absentee ballot in Maine?', '["When is the last day to ask for a mail ballot?","Absentee request deadline ME","Third business day rule"]', 'The deadline to request an absentee ballot without a special circumstances application is the close of business on the third business day prior to Election Day.', 'https://legislature.maine.gov/statutes/21-A/title21-Asec753-B.html', '21-A M.R.S. § 753-B(2)', '2026-05-12', 'static', 'statute_citation', 'All voters', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('2fbe3623854bbf9c', 'ME', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the polling place electioneering buffer zone in Maine?', '["How close to the door can I campaign in ME?","250-foot rule Maine voting","Campaign signs at polling places"]', 'Maine strictly enforces a 250-foot electioneering buffer zone around the entrance to any polling place or absentee voting location. Within this zone, no person may influence voters, distribute campaign literature, or display campaign signs.', 'https://legislature.maine.gov/statutes/21-A/title21-Asec682.html', '21-A M.R.S. § 682(2)', '2026-05-12', 'static', 'statute_citation', 'Campaigns and Poll Workers', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('93e0e4c46c4deef3', 'ME', '["federal","state"]', 'recall_rules', 'Can voters recall a statewide official or state legislator in Maine?', '["Statewide recall mechanism ME","How to recall the Governor in Maine","Can we recall a state senator?"]', 'Maine does not have a constitutional or statutory mechanism for the recall of statewide officials, state legislators, or federal representatives. Recall provisions exist strictly at the local level if authorized by a municipal charter.', 'https://legislature.maine.gov/const/', 'Maine Constitution', '2026-05-12', 'static', 'statute_citation', 'Voters and Campaigns', 'batch_2026-05-13T00-53-48_maine_full_v1')
INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('b69a57b848b25591', 'ME', '["county","municipal"]', 'recall_rules', 'How are local officials recalled in Maine?', '["Local recall threshold ME","Signatures needed to recall a mayor in Maine","School board recall signature requirements"]', 'The ability to recall a local official is entirely dependent on the specific municipality''s local charter. If a town does not have a charter provision explicitly detailing a recall mechanism, local officials cannot be recalled.', 'https://legislature.maine.gov/statutes/30-A/title30-Asec2505.html', '30-A M.R.S. § 2505', '2026-05-12', 'static', 'statute_citation', 'Local officials and recall committees', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('0cb8654dfd607b85', 'ME', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'What is a ''Challenged Ballot'' in Maine?', '["Provisional ballot Maine equivalent","Voting if my eligibility is questioned ME","How to cast a challenged ballot"]', 'A ''Challenged Ballot'' is Maine''s equivalent of a provisional ballot. If a voter''s eligibility is contested, they may still vote, but their ballot is secretly numbered, linked to a signed affidavit, and physically segregated so it can be reviewed later if the election margin is contested.', 'https://legislature.maine.gov/statutes/21-A/title21-Asec673.html', '21-A M.R.S. § 673', '2026-05-12', 'static', 'statute_citation', 'Voters and poll watchers', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('68236c8ed40d473d', 'ME', '["federal","state"]', 'redistricting', 'Who draws the state legislative and congressional district maps in Maine?', '["Maine Apportionment Commission process","Who is on the redistricting commission?","Does the legislature draw the maps in ME?"]', 'Redistricting is handled by the Maine Apportionment Commission, a 15-member bipartisan body consisting of legislative appointees and public members. The commission''s proposed maps must be subsequently approved by a two-thirds vote of the State Legislature.', 'https://www.maine.gov/sos/elections-voting/apportionment-commission', 'Maine Apportionment Commission', '2026-05-12', 'static', 'official_source_direct', 'State Legislative and Congressional Candidates', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('dd0aeec758b273d1', 'ME', '["federal","state"]', 'redistricting', 'Which congressional maps are in effect for the 2026 election cycle in Maine?', '["Did Maine redraw its congressional districts for 2026?","Redistricting status ME","Are we using new maps for Congress in 2026?"]', 'The maps drawn by the Apportionment Commission and adopted by the Legislature in 2021 (for the 2022 cycle) remain stable and in effect for the 2026 cycle without ongoing litigation.', 'https://www.maine.gov/sos/elections-voting/apportionment-commission', 'Maine Apportionment Commission', '2026-05-12', 'static', 'official_source_direct', 'U.S. House and State Legislative candidates', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('168dc0eae9725e9f', 'ME', '["state"]', 'election_dates', 'How are vacancies in the Maine State Legislature filled?', '["Special election for State Assembly ME","How is a vacant state senate seat filled?","Do special elections have primaries in ME?"]', 'Legislative vacancies are filled by special election. The Governor issues a proclamation to set the election date. There is no primary; instead, the respective political party committees for that district directly nominate candidates to appear on the special election ballot.', 'https://legislature.maine.gov/statutes/21-A/title21-Asec381.html', '21-A M.R.S. § 381', '2026-05-12', 'static', 'statute_citation', 'State Legislative Candidates and Party Caucuses', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('31a2ef56b33cdcc7', 'ME', '["federal"]', 'election_dates', 'How are vacancies in the U.S. House of Representatives filled in Maine?', '["Special election for Congress ME","Does the Governor appoint US House replacements in Maine?","Congressional vacancy procedure"]', 'Vacancies in the U.S. House of Representatives are filled exclusively by a special election called by the Governor. Unlike U.S. Senate vacancies, the Governor cannot appoint an interim U.S. Representative.', 'https://legislature.maine.gov/statutes/21-A/title21-Asec391.html', '21-A M.R.S. § 391', '2026-05-12', 'static', 'statute_citation', 'U.S. House candidates', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('8eca01890cb5be28', 'ME', '["state"]', 'election_dates', 'How are interim vacancies filled for the Secretary of State, Attorney General, or State Treasurer?', '["Who replaces the Maine Auditor if they resign?","Statewide office vacancy fill procedure","Does the Governor appoint the Attorney General?"]', 'If a vacancy occurs in the office of Secretary of State, Attorney General, or Treasurer while the Legislature is not in session, the Governor appoints an interim replacement who serves until the Legislature reconvenes and elects a successor.', 'https://legislature.maine.gov/const/#Article_V_Part_2', 'Maine Constitution Article V Part 2 § 2', '2026-05-12', 'static', 'statute_citation', 'Statewide executive officials', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('2656ba32de9da852', 'ME', '["judicial"]', 'election_dates', 'How are justices selected for the Maine Supreme Judicial Court, Superior Court, and District Court?', '["Are Supreme Court judges elected in ME?","Highest court selection process Maine","How long do ME highest court judges serve?"]', 'Judges in Maine are not elected. Justices for the Supreme Judicial Court, Superior Court, and District Court are nominated by the Governor, reviewed by the Legislature''s Judiciary Committee, and confirmed by the State Senate to serve seven-year terms.', 'https://legislature.maine.gov/const/#Article_V_Part_1', 'Maine Constitution Article V Part 1 § 8', '2026-05-12', 'static', 'statute_citation', 'Judicial nominees', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('6696027f8aca5210', 'ME', '["county"]', 'election_dates', 'How are County Sheriffs, Probate Judges, and County Commissioners selected in Maine?', '["Are sheriffs elected in ME?","Probate judge elections Maine","County commissioner term length"]', 'County Sheriffs, Probate Judges, and County Commissioners are directly elected by the voters in partisan elections to serve four-year terms.', 'https://legislature.maine.gov/statutes/30-A/title30-Asec401.html', '30-A M.R.S. § 401', '2026-05-12', 'static', 'statute_citation', 'County-level Candidates', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('bbb7a1ea2fb9e9ad', 'ME', '["federal","state","county"]', 'ballot_access', 'Who validates the signatures on a candidate''s nomination petition in Maine?', '["Where do I submit my petition signatures in ME?","Municipal clerk signature validation","Do I take my signatures straight to the Secretary of State?"]', 'Before submitting petitions to the Secretary of State, candidates must first submit their signature pages to the local municipal clerks where the signers reside. The municipal clerks physically verify the voters'' registration status and certify the signatures.', 'https://legislature.maine.gov/statutes/21-A/title21-Asec335.html', '21-A M.R.S. § 335(7)', '2026-05-12', 'static', 'statute_citation', 'All candidates', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('f493056af8a756b6', 'ME', '["state"]', 'finance_ethics', 'What were the 2015 ''Question 1'' reforms to the Maine Clean Election Act?', '["MCEA supplemental funding rules","How to get extra matching funds in ME","Question 1 Clean Elections"]', 'After the U.S. Supreme Court struck down Maine''s original matching funds mechanism in 2010, voters passed Question 1 in 2015. This restored competitiveness by allowing MCEA candidates in contested races to collect additional $5 qualifying contributions to unlock ''supplemental'' tiers of public funding beyond their initial base grant.', 'https://www.maine.gov/ethics/clean-elections', 'Maine Ethics Commission – MCEA', '2026-05-12', 'static', 'official_source_direct', 'MCEA Participating Candidates', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('935f9e6a8802e4b7', 'ME', '["state","county","municipal"]', 'finance_ethics', 'When must a candidate formally designate a campaign treasurer in Maine?', '["Designation of Treasurer deadline ME","When to register a campaign committee in Maine","Can I spend money before designating a treasurer?"]', 'Under Maine law, a candidate must appoint a campaign treasurer and file a registration with the Ethics Commission no later than 10 days after becoming a candidate, and strictly before accepting any contributions or making any expenditures.', 'https://legislature.maine.gov/statutes/21-A/title21-Asec1013-A.html', '21-A M.R.S. § 1013-A', '2026-05-12', 'static', 'statute_citation', 'All candidates and treasurers', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('b74ab91b945dcd42', 'ME', '["state","county","municipal"]', 'finance_ethics', 'Are candidates required to open a separate bank account for their campaign in Maine?', '["Campaign bank account rules ME","Can I use my personal checking account for donations?","Maine campaign depository requirements"]', 'Yes. Candidates must establish a separate campaign bank account in a financial institution located in Maine. Commingling campaign funds with personal or business funds is strictly prohibited.', 'https://legislature.maine.gov/statutes/21-A/title21-Asec1016.html', '21-A M.R.S. § 1016(1)', '2026-05-12', 'static', 'statute_citation', 'Campaign Treasurers', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('384cb68f9825abf3', 'ME', '["federal","state","county","municipal"]', 'finance_ethics', 'What are the disclosure requirements for mass mailings in Maine?', '["Do mailers need an ''Ad paid for by'' disclaimer?","Direct mail political rules Maine","Flyer disclaimer requirements"]', 'Any mass mailing (defined as a mailing of more than 500 pieces of identical or substantially similar mail) made to influence an election must clearly and conspicuously state the name and address of the person or committee who paid for and authorized the communication.', 'https://legislature.maine.gov/statutes/21-A/title21-Asec1014.html', '21-A M.R.S. § 1014', '2026-05-12', 'static', 'statute_citation', 'All Campaigns and Printers', 'batch_2026-05-13T00-53-48_maine_full_v1'),
  ('a9bf83415aaf5335', 'ME', '["federal","state","county","municipal"]', 'voter_interaction', 'Who has the authority to remove campaign signs placed illegally within the 250-foot buffer zone on Election Day?', '["Can poll workers take down my signs?","Sign removal buffer zone ME","Enforcement of polling place electioneering ban"]', 'The municipal clerk or the election warden has the legal authority and obligation to enforce the 250-foot electioneering buffer zone, which includes the immediate removal of any campaign signs or materials placed within that boundary on Election Day.', 'https://legislature.maine.gov/statutes/21-A/title21-Asec682.html', '21-A M.R.S. § 682', '2026-05-12', 'static', 'statute_citation', 'Campaigns and Poll Workers', 'batch_2026-05-13T00-53-48_maine_full_v1')
